//! AUTO-GENERATED by the spec-word-compliance workflow.
//!
//! Area: "Paragraph numbering reference, style ref, conditional formatting, and
//! text frames".
//!
//! Each `#[test]` encodes a behavioural constraint mined from ECMA-376 /
//! ISO 29500-1 / MS-OI29500 and the normative WML schema. A FAILING assertion
//! here means stemma diverges from Word — i.e. it encodes a REAL Word-compliance
//! gap, NOT a test to be weakened until it passes.
//!
//! Methodology (consumption vs. save): stemma round-trips untouched content
//! byte-verbatim, so `reserialize()` of an UNEDITED document reflects stemma's
//! verbatim-preservation contract, not Word's render normalization. Therefore
//! XML assertions here are confined to child/element ORDERING (Annex A schema
//! sequence) and structural validity ("opens clean"); Word CONSUMPTION semantics
//! (what text a marker contributes) are asserted on the READ side
//! (`read_accepted()/read_rejected().to_text()`).

use stemma::ExportOptions;
use stemma::api::{Document, validate};

// ─── Prelude / plumbing ─────────────────────────────────────────────────────

/// Build a minimal, valid `.docx` package. `body_xml` is the inner content of
/// `<w:body>` (paragraphs, sectPr, …). `extra_parts` are additional package
/// parts (e.g. `word/styles.xml`, `word/numbering.xml`); each gets a
/// `[Content_Types].xml` override and a `word/_rels/document.xml.rels` entry.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Content-type overrides + document rels for any extra parts.
    let mut overrides = String::new();
    let mut doc_rel_entries = String::new();
    for (rel_idx, (part, _xml)) in (1u32..).zip(extra_parts.iter()) {
        let (content_type, rel_type) = part_metadata(part);
        overrides.push_str(&format!(
            r#"<Override PartName="/{part}" ContentType="{content_type}"/>"#
        ));
        // Target is relative to the word/ directory (document.xml's location).
        let target = part.strip_prefix("word/").unwrap_or(part);
        doc_rel_entries.push_str(&format!(
            r#"<Relationship Id="rIdX{rel_idx}" Type="{rel_type}" Target="{target}"/>"#
        ));
    }

    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/><Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>{overrides}</Types>"#
    );
    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;
    let doc_rels = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">{doc_rel_entries}</Relationships>"#
    );

    use std::io::Write;
    use zip::write::FileOptions;
    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (part, xml) in extra_parts {
            zip.start_file(*part, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Content-type + relationship-type for a known package part.
fn part_metadata(part: &str) -> (&'static str, &'static str) {
    match part {
        "word/styles.xml" => (
            "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml",
            "http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles",
        ),
        "word/numbering.xml" => (
            "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml",
            "http://schemas.openxmlformats.org/officeDocument/2006/relationships/numbering",
        ),
        other => panic!("make_docx: unknown extra part {other} — add its content-type/rel-type"),
    }
}

/// Unzip a `.docx` and return `word/document.xml` as a UTF-8 string.
fn document_xml_of(docx: &[u8]) -> String {
    let archive = stemma::docx::DocxArchive::read(docx).expect("read docx archive");
    let bytes = archive
        .get("word/document.xml")
        .expect("document.xml present")
        .to_vec();
    String::from_utf8(bytes).expect("document.xml is utf8")
}

/// Parse, re-serialize through stemma's serializer, and return the resulting
/// `word/document.xml`. Valid only for ORDERING / structural-synthesis / validity
/// assertions (see module doc-comment).
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse");
    let out = doc.serialize(&ExportOptions::default()).expect("serialize");
    document_xml_of(&out)
}

/// True iff `first` occurs before `second` in `haystack` (both must be present).
fn occurs_before(haystack: &str, first: &str, second: &str) -> bool {
    match (haystack.find(first), haystack.find(second)) {
        (Some(a), Some(b)) => a < b,
        _ => false,
    }
}

