#[test]
fn outline_lvl_carries_no_text_and_opens_clean() {
    let body = r#"<w:p><w:pPr><w:outlineLvl w:val="0"/></w:pPr><w:r><w:t>Heading text</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let accepted = Document::parse(&b)
        .unwrap()
        .read_accepted()
        .unwrap()
        .to_text();
    assert_eq!(
        accepted.trim(),
        "Heading text",
        "§17.3.1.20 (ECMA-376 / ISO 29500-1 §17.3.1.20): outlineLvl does not affect the appearance of text, so the accepted text stream is exactly the run content with no injected level number"
    );

    let rejected = Document::parse(&b)
        .unwrap()
        .read_rejected()
        .unwrap()
        .to_text();
    assert_eq!(
        rejected.trim(),
        "Heading text",
        "§17.3.1.20: outlineLvl carries no run content; rejecting (there are no revisions) leaves the same run text"
    );

    let report = validate(&b);
    assert!(
        report.ok,
        "§17.3.1.20 / §17.18.10: outlineLvl val='0' is an in-range outline level (0..9); the paragraph is schema-valid and Word opens it without repair — issues: {:?}",
        report.issues
    );
}

#[test]
fn outline_lvl_body_text_value_9_round_trips() {
    // outlineLvl w:val="9" is the explicit "body text" marker (§17.3.1.20):
    // a directly-authored, in-range (ST_DecimalNumber 0..=9) value that is NOT a
    // heading. It must round-trip verbatim. Previously the parser discarded 9
    // ("we ignore it"), so the directly-authored element was a state-3 loss on
    // reserialize even though tables/paragraphs are rebuilt from the typed model.
    let body = r#"<w:p><w:pPr><w:outlineLvl w:val="9"/></w:pPr><w:r><w:t>Body para</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let report = validate(&b);
    assert!(
        report.ok,
        "§17.3.1.20 / §17.18.10: outlineLvl val='9' (body text) is an in-range outline value (0..=9); the paragraph is schema-valid and Word opens it without repair — issues: {:?}",
        report.issues
    );

    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"<w:outlineLvl w:val="9""#),
        "§17.3.1.20: a directly-authored outlineLvl val='9' (explicit body-text \
         marker) must survive reserialization — it must NOT be silently dropped \
         as 'not a heading'. reserialized document.xml was: {xml}"
    );
}

#[test]
fn direct_numpr_marker_not_in_text_stream() {
    let body = r#"<w:p><w:pPr><w:numPr><w:ilvl w:val="0"/><w:numId w:val="0"/></w:numPr></w:pPr><w:r><w:t>Body run</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let accepted = Document::parse(&b)
        .unwrap()
        .read_accepted()
        .unwrap()
        .to_text();
    assert_eq!(
        accepted.trim(),
        "Body run",
        "§17.3.1.19 (ECMA-376 / ISO 29500-1 §17.3.1.19): the numbering marker sits before the text flow and is not a run; accepted text is exactly the run content"
    );

    let rejected = Document::parse(&b)
        .unwrap()
        .read_rejected()
        .unwrap()
        .to_text();
    assert_eq!(
        rejected.trim(),
        "Body run",
        "§17.3.1.19: no run content is contributed by numPr; reject leaves the run text unchanged"
    );

    let report = validate(&b);
    assert!(
        report.ok,
        "§17.9.18: numId=0 is the 'no numbering' sentinel and is exempt from dangling-reference checks; the paragraph is well-formed and opens clean — issues: {:?}",
        report.issues
    );
}

#[test]
fn outline_lvl_before_div_id_ppr_order() {
    let body = r#"<w:p><w:pPr><w:outlineLvl w:val="2"/><w:divId w:val="123456"/></w:pPr><w:r><w:t>Tail order</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);

    // xmlRegex `<w:outlineLvl[^>]*/>\s*<w:divId` translated to a presence+order
    // check (regex crate unavailable): both elements present, outlineLvl first.
    assert!(
        xml.contains("<w:outlineLvl") && xml.contains("<w:divId"),
        "CT_PPrBase Annex A: re-serialized pPr must retain both outlineLvl (pos 31) and divId (pos 32) — got: {xml}"
    );
    assert!(
        occurs_before(&xml, "<w:outlineLvl", "<w:divId"),
        "CT_PPrBase Annex A sequence (ISO 29500-1 §17.3.1.20 / §17.3.1.10): outlineLvl (pos 31) must precede divId (pos 32) in the re-serialized pPr — got: {xml}"
    );

    let report = validate(&b);
    assert!(
        report.ok,
        "CT_PPrBase Annex A: outlineLvl-then-divId is the canonical order; the pPr is schema-valid and Word opens it without repair — issues: {:?}",
        report.issues
    );
}

#[test]
fn pstyle_before_framepr_ppr_order() {
    let styles = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:styles xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:style w:type="paragraph" w:styleId="BodyText"><w:name w:val="Body Text"/></w:style></w:styles>"#;
    let body = r#"<w:p><w:pPr><w:pStyle w:val="BodyText"/><w:framePr w:w="2191" w:h="811" w:hRule="exact" w:wrap="around" w:vAnchor="text" w:hAnchor="page" w:x="1921"/></w:pPr><w:r><w:t>Framed</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[("word/styles.xml", styles)]);
    let xml = reserialize(&b);

    assert!(
        xml.contains("<w:pStyle") && xml.contains("<w:framePr"),
        "CT_PPrBase Annex A: re-serialized pPr must retain both pStyle (pos 1) and framePr (pos 5) — got: {xml}"
    );
    assert!(
        occurs_before(&xml, "<w:pStyle", "<w:framePr"),
        "CT_PPrBase Annex A sequence (ISO 29500-1 §17.3.1.27 / §17.3.1.11): pStyle (pos 1) must precede framePr (pos 5) in the re-serialized pPr — got: {xml}"
    );

    let report = validate(&b);
    assert!(
        report.ok,
        "CT_PPrBase Annex A: pStyle-then-framePr is canonical and pStyle references a defined style; the pPr is schema-valid and Word opens it without repair — issues: {:?}",
        report.issues
    );
}

