#[test]
fn numpr_inside_paragraph_style_ilvl_not_ignored_by_word_opens_clean() {
    let styles = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:styles xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:style w:type="paragraph" w:styleId="ListPara"><w:name w:val="List Para"/><w:pPr><w:numPr><w:ilvl w:val="2"/><w:numId w:val="1"/></w:numPr></w:pPr></w:style></w:styles>"#;
    let numbering = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:numbering xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:abstractNum w:abstractNumId="0"><w:lvl w:ilvl="0"><w:start w:val="1"/><w:numFmt w:val="decimal"/><w:lvlText w:val="%1."/><w:lvlJc w:val="start"/></w:lvl><w:lvl w:ilvl="2"><w:start w:val="1"/><w:numFmt w:val="lowerLetter"/><w:lvlText w:val="%3)"/><w:lvlJc w:val="start"/></w:lvl></w:abstractNum><w:num w:numId="1"><w:abstractNumId w:val="0"/></w:num></w:numbering>"#;
    let body = r#"<w:p><w:pPr><w:pStyle w:val="ListPara"/></w:pPr><w:r><w:t>Numbered via style.</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(
        body,
        &[
            ("word/styles.xml", styles),
            ("word/numbering.xml", numbering),
        ],
    );

    let report = validate(&b);
    assert!(
        report.ok,
        "MS-OI29500 §2.1.50 / §17.3.1.19: a paragraph style with numPr (ilvl+numId) is well-formed; Word consumes it (does not ignore it) and opens the document without repair — issues: {:?}",
        report.issues
    );

    let accepted = Document::parse(&b)
        .unwrap()
        .read_accepted()
        .unwrap()
        .to_text();
    assert_eq!(
        accepted.trim(),
        "Numbered via style.",
        "§17.3.1.19 / MS-OI29500 §2.1.50: a style-level numPr governs the marker only; it injects no body run text, so accepted body text equals the run text"
    );
}

#[test]
fn cnfstyle_outside_table_cell_contents_ignored_on_read() {
    let body = r#"<w:p><w:pPr><w:cnfStyle w:firstRow="true" w:lastColumn="true" w:firstRowLastColumn="true"/></w:pPr><w:r><w:t>Plain body.</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let accepted = Document::parse(&b)
        .unwrap()
        .read_accepted()
        .unwrap()
        .to_text();
    assert_eq!(
        accepted.trim(),
        "Plain body.",
        "§17.3.1.8: cnfStyle outside a table cell is ignored on read; it injects no text, so accepted body text equals the run text"
    );

    let rejected = Document::parse(&b)
        .unwrap()
        .read_rejected()
        .unwrap()
        .to_text();
    assert_eq!(
        rejected.trim(),
        "Plain body.",
        "§17.3.1.8: the cnfStyle mask carries no tracked-change or run content; rejected body text equals the run text"
    );

    let report = validate(&b);
    assert!(
        report.ok,
        "MS-OI29500 §2.1.41 / §17.3.1.8: a cnfStyle on a non-cell paragraph is a tolerated no-op; Word opens it without repair — issues: {:?}",
        report.issues
    );
}

#[test]
fn cnfstyle_val_12bit_mask_opens_clean_no_body_leak() {
    let body = r#"<w:p><w:pPr><w:cnfStyle w:val="100000000000"/></w:pPr><w:r><w:t>Cell text</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let report = validate(&b);
    assert!(
        report.ok,
        "ST_Cnf <xsd:length value=\"12\"/> + pattern [01]* (ECMA-376 Part 4 §14.3.1.1, §A.4): a 12-char binary @val is schema-valid; MS-OI29500 §2.1.41 says Word reads @val, so a Word-faithful validator reports no errors — issues: {:?}",
        report.issues
    );

    let accepted = Document::parse(&b)
        .unwrap()
        .read_accepted()
        .unwrap()
        .to_text();
    assert_eq!(
        accepted.trim(),
        "Cell text",
        "§17.3.1.8: cnfStyle is paragraph conditional-formatting metadata, never run content; accepting leaves body text exactly the run text with no mask leakage"
    );

    let rejected = Document::parse(&b)
        .unwrap()
        .read_rejected()
        .unwrap()
        .to_text();
    assert_eq!(
        rejected.trim(),
        "Cell text",
        "§17.3.1.8: a cnfStyle mask carries no tracked content, so rejected text equals the bare run text"
    );
}

