    let body = r#"<w:p><w:pPr><w:framePr w:dropCap="drop" w:lines="10" w:wrap="around" w:vAnchor="text" w:hAnchor="text"/></w:pPr><w:r><w:t>O</w:t></w:r></w:p><w:p><w:r><w:t>nce upon a time.</w:t></w:r></w:p><w:sectPr/>"#;
